#include <bits/stdc++.h>
using namespace std;
int main(){long long N,M;cin>>N>>M;vector<long long>a(N);long long hi=0;for(auto&x:a){cin>>x;hi=max(hi,x);}long long lo=0,ans=0;while(lo<=hi){long long mid=(lo+hi)/2,s=0;for(auto x:a)if(x>mid)s+=x-mid;if(s>=M){ans=mid;lo=mid+1;}else hi=mid-1;}cout<<ans<<"\n";}
